import anthropic
import json

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "search_orders",
        "description": "Search a customer's order history by order ID or date range.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Order ID or date in YYYY-MM-DD format."},
            },
            "required": ["query"],
        },
    },
    {
        "name": "get_account_info",
        "description": "Retrieve account details (name, email, subscription tier) for the current user.",
        "input_schema": {"type": "object", "properties": {}, "required": []},
    },
]


def call(user_message: str, tool_choice=None) -> dict:
    kwargs = {
        "model": "claude-haiku-4-5-20251001",
        "max_tokens": 300,
        "tools": TOOLS,
        "messages": [{"role": "user", "content": user_message}],
    }
    if tool_choice:
        kwargs["tool_choice"] = tool_choice
    response = client.messages.create(**kwargs)
    tool_calls = [
        {"name": b.name, "input": b.input}
        for b in response.content if b.type == "tool_use"
    ]
    text = next((b.text for b in response.content if hasattr(b, "text")), None)
    return {"tool_calls": tool_calls, "text": text, "stop_reason": response.stop_reason}


# --- Default: model decides whether to call a tool ---
print("Default (auto):")
result = call("What is my subscription tier?")
print(f"  Tool calls: {result['tool_calls']}")
print(f"  Text: {result['text']}")

# --- Force a specific tool regardless of message ---
print("\nForced (specific):")
result = call(
    "Hello!",
    tool_choice={"type": "tool", "name": "get_account_info"},
)
print(f"  Tool calls: {result['tool_calls']}")

# --- Force some tool to be called (model picks which) ---
print("\nForced (any):")
result = call(
    "What's my order status?",
    tool_choice={"type": "any"},
)
print(f"  Tool calls: {result['tool_calls']}")

# --- Prevent any tool call ---
print("\nNo tools (none):")
result = call(
    "What is my subscription tier?",
    tool_choice={"type": "none"},
)
print(f"  Text: {result['text']}")

import anthropic

client = anthropic.Anthropic()

# Two search tools with adjacent scopes — descriptions disambiguate them
OVERLAPPING_TOOLS = [
    {
        "name": "search_product_catalogue",
        "description": (
            "Searches the product catalogue for items, prices, and availability. "
            "Use when the user asks about products, SKUs, stock, or pricing. "
            "Does NOT search orders, accounts, or support history."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Product name, SKU, or category."},
            },
            "required": ["query"],
        },
    },
    {
        "name": "search_support_articles",
        "description": (
            "Searches the help centre for how-to articles, FAQs, and troubleshooting guides. "
            "Use when the user has a how-to question or reports a problem. "
            "Does NOT search the product catalogue or order history."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Support question or error description."},
            },
            "required": ["query"],
        },
    },
]

TEST_MESSAGES = [
    "How do I reset my password?",
    "Do you have the blue jacket in size M?",
    "I'm getting an error when I try to checkout.",
]

for msg in TEST_MESSAGES:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=150,
        tools=OVERLAPPING_TOOLS,
        messages=[{"role": "user", "content": msg}],
    )
    tool_calls = [b.name for b in response.content if b.type == "tool_use"]
    print(f"'{msg}'")
    print(f"  → {tool_calls if tool_calls else 'no tool'}")
